import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './CreateCampaign.css';

const CATEGORIES = ['Medical', 'Education', 'Social', 'Environment', 'Animal Welfare', 'Disaster Relief', 'Other'];

const CreateCampaign = () => {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    goal: '',
    category: '',
    imageUrl: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData((prev) => ({ ...prev, [e.target.name]: e.target.value }));
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const { title, description, goal, category } = formData;

    if (!title.trim() || !description.trim() || !goal || !category) {
      setError('Title, description, fundraising goal, and category are all required.');
      return;
    }

    if (title.trim().length < 5) {
      setError('Campaign title must be at least 5 characters.');
      return;
    }

    if (description.trim().length < 20) {
      setError('Campaign description must be at least 20 characters.');
      return;
    }

    const parsedGoal = Number(goal);
    if (isNaN(parsedGoal) || parsedGoal < 100) {
      setError('Fundraising goal must be at least ₹100.');
      return;
    }

    try {
      setLoading(true);
      setError('');

      const { data } = await axios.post('/api/campaigns', {
        title: formData.title.trim(),
        description: formData.description.trim(),
        goal: parsedGoal,
        category: formData.category,
        imageUrl: formData.imageUrl.trim()
      });

      navigate(`/campaigns/${data.campaign._id}`);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create campaign. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const goalAmount = Number(formData.goal);
  const estimatedDonors = goalAmount > 0 ? Math.ceil(goalAmount / 500) : 0;

  return (
    <div className="create-campaign-page">
      <div className="create-bg">
        <div className="create-orb"></div>
      </div>

      <div className="container">
        <div className="create-layout">
          {/* Form */}
          <div className="create-form-card" id="create-campaign-container">
            <div className="create-header">
              <h1 className="page-title">🚀 Start a Campaign</h1>
              <p style={{ color: 'var(--text-secondary)', marginTop: '0.5rem' }}>
                Share your cause with the world and start receiving support.
              </p>
            </div>

            {error && (
              <div className="alert alert-error" id="create-error-alert" role="alert">
                <span>⚠️</span>
                <p>{error}</p>
              </div>
            )}

            <form onSubmit={handleSubmit} noValidate id="create-campaign-form">
              <div className="form-group">
                <label className="form-label" htmlFor="campaign-title">Campaign Title *</label>
                <input
                  id="campaign-title"
                  name="title"
                  type="text"
                  className="form-input"
                  placeholder="e.g., Help Raj get surgery for heart disease"
                  value={formData.title}
                  onChange={handleChange}
                  maxLength={100}
                  required
                />
                <span className="char-count">{formData.title.length}/100</span>
              </div>

              <div className="form-group">
                <label className="form-label" htmlFor="campaign-description">Campaign Description *</label>
                <textarea
                  id="campaign-description"
                  name="description"
                  className="form-input"
                  placeholder="Tell your story. Explain who needs help, why they need it, and how funds will be used..."
                  value={formData.description}
                  onChange={handleChange}
                  rows={6}
                  required
                ></textarea>
                <span className="char-count">{formData.description.length} characters</span>
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label className="form-label" htmlFor="campaign-goal">Fundraising Goal (₹) *</label>
                  <input
                    id="campaign-goal"
                    name="goal"
                    type="number"
                    className="form-input"
                    placeholder="e.g., 500000"
                    value={formData.goal}
                    onChange={handleChange}
                    min={100}
                    required
                  />
                </div>

                <div className="form-group">
                  <label className="form-label" htmlFor="campaign-category">Category *</label>
                  <select
                    id="campaign-category"
                    name="category"
                    className="form-input"
                    value={formData.category}
                    onChange={handleChange}
                    required
                  >
                    <option value="" disabled>Select a category</option>
                    {CATEGORIES.map((cat) => (
                      <option key={cat} value={cat}>{cat}</option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="form-group">
                <label className="form-label" htmlFor="campaign-image">Campaign Image URL (optional)</label>
                <input
                  id="campaign-image"
                  name="imageUrl"
                  type="url"
                  className="form-input"
                  placeholder="https://example.com/image.jpg"
                  value={formData.imageUrl}
                  onChange={handleChange}
                />
                {formData.imageUrl && (
                  <div className="image-preview" id="image-preview">
                    <img
                      src={formData.imageUrl}
                      alt="Campaign preview"
                      onError={(e) => {
                        e.target.onerror = null;
                        e.target.style.display = 'none';
                      }}
                    />
                  </div>
                )}
              </div>

              <button
                type="submit"
                className="btn btn-primary btn-full btn-lg"
                disabled={loading}
                id="btn-create-submit"
              >
                {loading ? (
                  <>
                    <span className="spinner"></span>
                    Creating Campaign...
                  </>
                ) : (
                  '🚀 Launch Campaign'
                )}
              </button>
            </form>
          </div>

          {/* Preview Sidebar */}
          <div className="create-sidebar">
            <div className="card preview-card" id="campaign-preview">
              <h3 style={{ marginBottom: '1.25rem', color: 'var(--text-secondary)', fontSize: '0.85rem', textTransform: 'uppercase', letterSpacing: '0.07em' }}>
                Live Preview
              </h3>

              {formData.imageUrl && (
                <div className="preview-image">
                  <img
                    src={formData.imageUrl}
                    alt="preview"
                    onError={(e) => { e.target.style.display = 'none'; }}
                  />
                </div>
              )}

              {formData.category && (
                <span className="badge badge-primary" style={{ marginBottom: '0.75rem' }}>
                  {formData.category}
                </span>
              )}

              <h4 style={{ marginBottom: '0.5rem', lineHeight: 1.4 }}>
                {formData.title || 'Your campaign title will appear here'}
              </h4>

              <p style={{ fontSize: '0.875rem', color: 'var(--text-secondary)', marginBottom: '1rem', lineHeight: 1.6 }}>
                {formData.description
                  ? (formData.description.substring(0, 120) + (formData.description.length > 120 ? '...' : ''))
                  : 'Your campaign description will appear here...'}
              </p>

              {goalAmount > 0 && (
                <div>
                  <div className="progress-bar-wrapper" style={{ marginBottom: '0.5rem' }}>
                    <div className="progress-bar-fill" style={{ width: '0%' }}></div>
                  </div>
                  <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.85rem' }}>
                    <span style={{ color: 'var(--success)', fontWeight: 600 }}>₹0 raised</span>
                    <span style={{ color: 'var(--text-muted)' }}>
                      Goal: ₹{goalAmount.toLocaleString('en-IN')}
                    </span>
                  </div>
                </div>
              )}

              {estimatedDonors > 0 && (
                <div className="preview-stat" style={{ marginTop: '1rem', padding: '0.75rem', background: 'rgba(124,58,237,0.08)', borderRadius: 'var(--radius-md)', fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                  💡 At avg. ₹500/donor, you need approx.{' '}
                  <strong style={{ color: 'var(--primary-light)' }}>{estimatedDonors} donors</strong> to reach your goal.
                </div>
              )}
            </div>

            <div className="card tips-card" id="tips-card">
              <h3 style={{ marginBottom: '1rem', fontSize: '0.95rem', color: 'var(--text-primary)' }}>
                ✨ Tips for Success
              </h3>
              <ul style={{ display: 'flex', flexDirection: 'column', gap: '0.6rem', paddingLeft: '1rem' }}>
                {[
                  'Be specific about how you will use the funds',
                  'Add a real photo to build trust with donors',
                  'Share a personal story to create emotional connection',
                  'Set a realistic goal based on your actual needs',
                  'Update donors with progress after receiving funds'
                ].map((tip, i) => (
                  <li key={i} style={{ color: 'var(--text-secondary)', fontSize: '0.85rem', lineHeight: 1.5 }}>
                    {tip}
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CreateCampaign;
